val uiState: StateFlow<SearchUiState> = criteria
    .map { it.normalized() }
    .debounce(300)
    .distinctUntilChanged()
    .flatMapLatest { value ->
        if (value.keyword.isBlank()) {
            flowOf(SearchUiState.Idle)
        } else {
            flow {
                emit(SearchUiState.Content(repository.search(value)))
            }
            .onStart { emit(SearchUiState.Loading(value)) }
            .catch { error ->
                if (error is CancellationException) throw error
                emit(SearchUiState.Error(value, error.toUiError()))
            }
        }
    }
    .stateIn(
        scope = viewModelScope,
        started = SharingStarted.WhileSubscribed(5_000),
        initialValue = SearchUiState.Idle
    )

fun observeConnectivity(): Flow<Boolean> = callbackFlow {
    val callback = object : NetworkCallback() {
        override fun onAvailable(network: Network) { trySend(true) }
        override fun onLost(network: Network) { trySend(false) }
    }

    connectivityManager.registerDefaultNetworkCallback(callback)
    awaitClose {
        connectivityManager.unregisterNetworkCallback(callback)
    }
}.distinctUntilChanged()
